from typing import List, Optional, Any, Literal, Union
from leann import LeannBuilder
from leann.api import LeannSearcher, SearchResult
from pathlib import Path


def build_multiple_indexes(
    index_configs: List[dict[str, Any]], base_dir: str
) -> dict[str, str]:
    if not index_configs:
        raise ValueError("index_configs cannot be empty")

    # Validate each config has required fields
    for config in index_configs:
        if "index_name" not in config:
            raise ValueError("Each config must have 'index_name'")
        if "documents" not in config:
            raise ValueError("Each config must have 'documents'")

    # Ensure base directory exists
    Path(base_dir).mkdir(parents=True, exist_ok=True)

    index_map = {}
    for config in index_configs:
        index_name = config["index_name"]
        documents = config["documents"]
        backend_name = config.get("backend_name", "hnsw")

        # Validate documents structure
        for doc in documents:
            if not isinstance(doc, dict) or "text" not in doc:
                raise ValueError("Invalid document structure; 'text' is required")

        index_path = Path(base_dir) / f"{index_name}.leann"
        builder = LeannBuilder(backend_module_name=backend_name)
        builder.build_index(documents, index_path=str(index_path))
        index_map[index_name] = str(index_path)

    return index_map


def unified_search_across_indexes(
    index_paths: dict[str, str],
    query: str,
    top_k_per_index: int = 3,
    global_top_k: Optional[int] = None,
) -> list[SearchResult]:
    merged_results = []

    for index_name, index_path in index_paths.items():
        try:
            searcher = LeannSearcher(index_path=index_path)
            results = searcher.search(query, top_k=top_k_per_index)
            merged_results.extend(results)
        except Exception as e:
            print(f"Warning: Could not search in index '{index_name}': {e}")

    # Deduplicate by text content
    seen_texts = set()
    unique_results = []
    for result in merged_results:
        text = result.text
        if text not in seen_texts:
            seen_texts.add(text)
            unique_results.append(result)

    # Sort by score descending
    sorted_results = sorted(unique_results, key=lambda x: x.score, reverse=True)

    # Apply global top_k if specified
    if global_top_k is not None:
        sorted_results = sorted_results[:global_top_k]

    return sorted_results

