from collections import defaultdict


def apply_dynamic_filters(
    search_results: list[SearchResult],
    filter_specs: dict[str, dict[str, Any]],
    filter_logic: str = "AND",
) -> list[SearchResult]:
    # Convert filter specifications into a list of filter dictionaries
    filters = []
    for field, condition in filter_specs.items():
        for operator, value in condition.items():
            filters.append(
                {
                    "field": field,
                    "operator": operator,
                    "value": value,
                }
            )

    # Create MetadataFilterEngine with the specified logic
    filter_engine = MetadataFilterEngine(filters, logic=filter_logic)

    # Apply filters to SearchResult objects
    filtered_results = []
    for result in search_results:
        if filter_engine.evaluate(result.metadata):
            filtered_results.append(result)

    return filtered_results

