def search_and_aggregate_scores(
    index_path: str,
    query: str,
    aggregate_by_field: str,
    top_k: int = 10
) -> dict[str, dict[str, float]]:
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError("Index file not found")

    results = searcher.search(query, top_k=top_k)
    aggregates = defaultdict(list)

    for result in results:
        field_value = result.metadata.get(aggregate_by_field)
        if field_value is not None:
            aggregates[field_value].append(result.score)

    result_dict = {}
    for field_value, scores in aggregates.items():
        if not scores:
            continue
        count = len(scores)
        avg_score = sum(scores) / count
        max_score = max(scores)
        min_score = min(scores)
        result_dict[field_value] = {
            "count": float(count),  # Convert to float to match return type annotation
            "avg_score": avg_score,
            "max_score": max_score,
            "min_score": min_score
        }

    return result_dict

