    case_sensitive: bool = False
) -> List[dict[str, Any]]:
    if not pattern:
        raise ValueError("pattern cannot be empty")
    meta_path = Path(index_path) / "passages.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError("Index metadata file not found")
    pm = PassageManager(index_path)
