def build_index_with_metadata_validation(
    documents: List[dict],
    index_path: str,
    required_metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    if not documents:
        raise ValueError("documents list is empty")

    # Validate required metadata fields and 'text' presence
    for doc in documents:
        if 'text' not in doc:
            raise ValueError("document missing 'text' field")
        if required_metadata_fields:
            if 'metadata' in doc:
                for field in required_metadata_fields:
                    if field not in doc['metadata']:
                        raise ValueError("missing required metadata fields")

    # Prepare passages for LEANN Builder
    passages = []
    for i, doc in enumerate(documents):
        passages.append({
            'id': str(i),
            'text': doc['text'],
            'metadata': doc.get('metadata', {})
        })

    # Build the index
    builder = LeannBuilder(backend_module_name=backend_name)
    builder.build_index(passages, index_path)

    return index_path

