        raise ValueError("index_paths cannot be empty")

    results = {}
    for index_path in index_paths:
        searcher = LeannSearcher(index_path)
        res = searcher.search(query, top_k=top_k_per_index)
        results[index_path] = res
    return results

def merge_search_results(
    results_by_index: Dict[str, List[SearchResult]],
    global_top_k: int = 10,
    deduplicate: bool = True
) -> List[SearchResult]:
    merged = []
    for index_list in results_by_index.values():
        merged.extend(index_list)

    merged.sort(key=lambda x: x.score, reverse=True)

    if deduplicate:
        seen_texts = set()
        deduped = []
        for result in merged:
            text = result.text
            if text not in seen_texts:
                seen_texts.add(text)
                deduped.append(result)
        merged = deduped

    return merged[:global_top_k]

