from collections import Counter, defaultdict

def get_index_statistics(index_path: str) -> Dict[str, Any]:
    try:
        pm = PassageManager(index_path)
    except FileNotFoundError:
        raise FileNotFoundError("Index metadata file not found")
    total = len(pm.passages)
    fields = set()
    field_values = defaultdict(Counter)
    for passage in pm.passages.values():
        meta = passage.meta
        for field in meta:
            fields.add(field)
            field_values[field].update([meta[field]])
    return {
        "total_passages": total,
        "metadata_fields": sorted(fields),
        "field_value_counts": {k: dict(v) for k, v in field_values.items()}
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    try:
        pm = PassageManager(index_path)
    except FileNotFoundError:
        raise FileNotFoundError("Index metadata file not found")
    total = len(pm.passages)
    covered = 0
    field_coverages = defaultdict(int)
    missing_fields = set(required_fields)
    for passage in pm.passages.values():
        has_all = True
        for field in required_fields:
            if field not in passage.meta:
                has_all = False
                break
        if has_all:
            covered += 1
            for field in required_fields:
                field_coverages[field] += 1
        else:
            for field in required_fields:
                if field in passage.meta:
                    missing_fields.discard(field)
    coverage_percent = (covered / total) * 100 if total > 0 else 0
    field_coverage = {field: (count / total) * 100 for field, count in field_coverages.items()}
    return {
        "coverage_percentage": coverage_percent,
        "field_coverage": field_coverage,
        "missing_fields": list(missing_fields)
    }

